        "speaker": "agent",
        "sequenceIndex": 47,
        "text": "Is there anything else I can help you with today, Ms. Park?",
        "startTime": 401.91,
        "endTime": 411.3,
        "timestamp": "06:41",
        "emotion": "neutral",
        "acousticEmotion": "neutral",
        "confidence": 0.593,
