        "speaker": "customer",
        "sequenceIndex": 46,
        "text": "Oh! Two hundred and twelve Mbps! It's working!",
        "startTime": 308.32,
        "endTime": 314.14,
        "timestamp": "05:08",
        "emotion": "happy",
        "acousticEmotion": "happy",
