        "interactionId": "98834515-c16b-58f2-9b5a-f3d8ecdfb139",
        "speaker": "agent",
        "sequenceIndex": 37,
        "text": "All right. Both tickets are open.",
        "startTime": 331.75,
        "endTime": 341.27,
        "timestamp": "05:31",
