        "interactionId": "cb6dbe2f-e487-5693-9c99-73e7c80328c6",
        "speaker": "customer",
        "sequenceIndex": 25,
        "text": "Fine.",
        "startTime": 225.68,
        "endTime": 233.54,
        "timestamp": "03:45",
        "emotion": "angry",
        "acousticEmotion": "angry",
        "confidence": 0.401,
