        "interactionId": "cb6dbe2f-e487-5693-9c99-73e7c80328c6",
        "speaker": "agent",
        "sequenceIndex": 28,
        "text": "That's what it looks like. It's a billing error, and it's eligible for full reversal under our refund policy.",
        "startTime": 251.87,
        "endTime": 260.12,
        "timestamp": "04:11",
        "emotion": "happy",
