        "interactionId": "204f6ce9-2307-56ca-ae61-1110269449ff",
        "speaker": "agent",
        "sequenceIndex": 30,
        "text": "That's the answer. Two hundred and eighty-six down on a three hundred plan is well within range — most plans don't hit perfect peak because of normal overhead, but two-eighty-six is the line doing its job.",
        "startTime": 256.44,
        "endTime": 265.4,
