        "interactionId": "204f6ce9-2307-56ca-ae61-1110269449ff",
        "speaker": "agent",
        "sequenceIndex": 32,
        "text": "Almost certainly WiFi interference or distance. A few quick questions — where in the house is the router, and where are you usually using your phone?",
        "startTime": 274.77,
        "endTime": 283.66,
        "timestamp": "04:34",
        "emotion": "neutral",
        "acousticEmotion": "neutral",
        "confidence": 0.772,
