        "id": "76c6a464-a316-599d-958b-67d4f75a3486",
        "interactionId": "204f6ce9-2307-56ca-ae61-1110269449ff",
        "speaker": "customer",
        "sequenceIndex": 33,
        "text": "The router is in the basement closet where the cable comes in. I'm usually upstairs in the living room, two floors up. There's a thick floor in between.",
