        "interactionId": "47b132fa-82d8-51e1-b3b9-f4a7c7081cd6",
        "speaker": "agent",
        "sequenceIndex": 39,
        "text": "And again — I really am sorry for how today went. That's not the experience we want anyone walking away with.",
        "startTime": 335.06,
        "endTime": 342.9,
        "timestamp": "05:35",
        "emotion": "happy",
