        "id": "8d9b92c8-81e6-563a-8e45-a42ea61bf07e",
        "interactionId": "abc5eb1d-64b1-55e4-8a00-bbec382e4f9e",
        "speaker": "customer",
        "sequenceIndex": 25,
        "text": "Oh, that's such a relief.",
        "startTime": 202.47,
        "endTime": 211.33,
        "timestamp": "03:22",
        "emotion": "happy",
        "acousticEmotion": "happy",
        "confidence": 0.421,
        "textEmotion": "happy",
        "textConfidence": 0.3,
        "fusedEmotion": "happy",
