        "interactionId": "abc5eb1d-64b1-55e4-8a00-bbec382e4f9e",
        "speaker": "agent",
        "sequenceIndex": 29,
        "text": "Group one: x-seven-q-m. Group two: r-two-n-p. Group three: t-eight-f-j. Group four: w-five-k-d.",
        "startTime": 239.0,
        "endTime": 247.92,
        "timestamp": "03:59",
        "emotion": "neutral",
