        "interactionId": "9f3735a4-db67-5112-8602-fa61caf25536",
        "speaker": "agent",
        "sequenceIndex": 34,
        "text": "Three things, in this order. One — change the password on your NexaLink account portal. Don't do it from a saved password manager entry; type a new one in fresh. Use at least sixteen characters with a mix of letters, numbers, and symbols. Don't reuse anything you use elsewhere.",
        "startTime": 290.97,
        "endTime": 299.96,
        "timestamp": "04:50",
        "emotion": "neutral",
