        "speaker": "agent",
        "sequenceIndex": 36,
        "text": "Two — change the password on the email address that's linked to this account. If your email is compromised, anyone can request a password reset on any other account that uses that email. So email gets locked down too.",
        "startTime": 309.02,
        "endTime": 317.51,
