        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "agent",
        "sequenceIndex": 22,
        "text": "Category one is non-essential personal data — your name, address, contact details, service preferences, support call history, marketing-consent records. All of that will be purged within thirty days of the confirmed deletion request. After that, it is permanently removed.",
        "startTime": 193.9,
