        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "agent",
        "sequenceIndex": 28,
        "text": "Category three is the audio recording of any past support calls you made to us — those have a ninety-day retention regardless, so most of yours will age out naturally. Anything still in the ninety-day window gets included in the deletion.",
        "startTime": 244.46,
        "endTime": 253.2,
