        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "customer",
        "sequenceIndex": 29,
        "text": "Including this call?",
        "startTime": 253.55,
        "endTime": 262.54,
        "timestamp": "04:13",
        "emotion": "neutral",
        "acousticEmotion": "neutral",
        "confidence": 0.637,
        "textEmotion": "sad",
