        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "agent",
        "sequenceIndex": 30,
        "text": "This call is processed under the same rule — ninety days from today, then auto-deleted unless you've explicitly asked us to include it in the broader erasure, in which case I add a note to the ticket. Would you like it included?",
        "startTime": 262.71,
        "endTime": 270.32,
        "timestamp": "04:22",
        "emotion": "happy",
        "acousticEmotion": "happy",
        "confidence": 0.35,
