        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "agent",
        "sequenceIndex": 32,
        "text": "Noted on the ticket. Now I'm opening the Data Deletion request and routing it to our Data Compliance Officer. Their team owns these end-to-end.",
        "startTime": 279.26,
        "endTime": 288.0,
        "timestamp": "04:39",
