        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "agent",
        "sequenceIndex": 34,
        "text": "You will receive a written acknowledgement of the request within seventy-two hours, with the case reference number. The actual deletion of category one and category three data is completed within thirty days of that acknowledgement. You'll receive a second written confirmation when deletion is complete. Both go to the email address on the closed account, so make sure that mailbox is still active for the next forty days.",
        "startTime": 295.98,
        "endTime": 303.86,
        "timestamp": "04:55",
        "emotion": "neutral",
        "acousticEmotion": "neutral",
        "confidence": 0.627,
