        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "customer",
        "sequenceIndex": 41,
        "text": "Yes. That's exactly what I needed.",
        "startTime": 353.81,
        "endTime": 363.06,
        "timestamp": "05:53",
        "emotion": "happy",
        "acousticEmotion": "happy",
        "confidence": 0.433,
