        "interactionId": "03b73e20-d3f0-5ffb-ab74-34f7657ee8f5",
        "speaker": "agent",
        "sequenceIndex": 42,
        "text": "You're welcome. I want to also say — the way you came in with the framing already clear made this very efficient. Most data deletion calls are slower because we have to walk customers through what their actual rights are first.",
        "startTime": 363.45,
        "endTime": 371.72,
        "timestamp": "06:03",
