        "interactionId": "f0e6d063-a355-55c5-bb67-b7c52e589e5a",
        "speaker": "agent",
        "sequenceIndex": 28,
        "text": "And honestly, this is closer to what your actual usage justifies. We were never going to deliver more value with the higher-tier plan if you weren't using it.",
        "startTime": 234.31,
        "endTime": 243.88,
        "timestamp": "03:54",
