        "interactionId": "f0e6d063-a355-55c5-bb67-b7c52e589e5a",
        "speaker": "agent",
        "sequenceIndex": 30,
        "text": "No contract extension required. Your current term doesn't change. The loyalty credit is month-to-month — if you ever decide to leave during the twelve months, no early-termination penalty is added by accepting this credit.",
